{
  "name": "Weatherization Assistance Program (WAP)",
  "eligibility": {
    "age": 18,
    "income_limits": "Based on 200% of the federal poverty level for PY2025 (7/1/2025-6/30/2026). Exact table not fully listed in sources, but older 2016 example: 1-person household $1,962/month; 2-person $2,655; 3-person $3,348; 4-person $4,042; 5-person $4,735. Current PY2025 limits issued 9/23/2025 via Notice WAP-2025-01; contact LHC for full table as limits change 6/30/2026[1][2][6]",
    "asset_limits": "No asset limits mentioned in sources[1][2]",
    "other_requirements": ["Household income at or below 200% poverty level", "Priority for elderly (60+), families with children under 18, disabled (SSI-established)", "Homeowners or renters (renters need landlord permission)", "At least one household member 18+", "Property not scheduled for government acquisition/clearance", "Valid photo ID and SS cards for members 18+"][1][2][3][4][6]
  },
  "benefits": {
    "type": "service",
    "value": "No-cost energy efficiency services including insulation improvements, air sealing, HVAC repairs/upgrades, energy-efficient lighting/appliances, heating/cooling system improvements, blower door audits, basic health/safety checks. No specific dollar amounts or hours; services based on computerized energy audits[1][4][5][6]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Contact local WAP provider or LHC Energy Assistance Department (phone not listed; use lhc.la.gov/weatherization)", "Mail/fax/email to local providers e.g. Quad Area (45300 N. Baptist Rd., specific address varies)", "In-person at local offices e.g. LaSalle Community Action Association, St. Mary Community Action Agency, Quad Area[1][3][4][6][7]"],
    "processing_time": "Not specified in sources",
    "waitlist": "Availability not guaranteed; waiting lists used with priority points for elderly, families, disabled[1]",
    "forms": ["WAP Application (includes Zero Income Statement if applicable, Lessor/Owner Agreement for renters)", "Completed with all signatures[3]"],
    "documents": ["Last 4 consecutive pay stubs or 30-day proof of income for all 18+", "Proof of unearned income (SS, pension, disability, unemployment)", "Proof of address (lease, deed, rent receipt)", "Current gas/electric/propane bill", "Photo ID for all 18+", "SS cards for all household members", "For renters: Lessor/Owner Agreement and lease", "For owners: Proof of ownership", "Disability/SS award letters if applicable[1][3][4][8]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Services in every parish, but administered by local providers[1][4][6]",
    "regional_variations": "Administered by regional subgrantees e.g. LaSalle Community Action (North/Central incl. Rapides, Caddo, etc.), Quad Area, St. Mary CAA; potential waitlist/availability differences by region/provider[1][4][6][7]",
    "offices_or_providers": ["Louisiana Housing Corporation (LHC) oversees", "LaSalle Community Action Association (North/Central)", "Quad Area Weatherization", "St. Mary Community Action Agency", "Others per parish; contact LHC for local[1][4][6][7]"]
  },
  "official_source": "https://www.lhc.la.gov/weatherization",
  "gotchas": ["Availability not guaranteed; waiting lists with priority points (elderly 60+, kids <18, SSI-disabled get extras)", "Renters need landlord written approval", "Income proof strict (last 4 stubs or 30 days; zero income needs form)", "PY2025 income limits change 6/30/2026; verify current via LHC", "Must be 18+ to apply, priority for 60+", "Additional docs may be required[1][2][3][6]"],
  "data_shape_notes": "Statewide via LHC with local subgrantees; priority tiers for elderly/families/disabled; income at 200% poverty (table via annual notice); waitlists common; no fixed processing times listed"
}

{
  "name": "Louisiana Senior Health Insurance Information Program (SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; open to all Medicare beneficiaries, including those with limited incomes, under age 65 with disabilities, and dually eligible for Medicare and Medicaid[2][4].",
    "asset_limits": "No asset limits or tests apply[2].",
    "other_requirements": ["Must be a Medicare beneficiary (Part A, Part B, Medicare Advantage, or Part D enrollees); families and caregivers also eligible for assistance[1][2][4]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free, unbiased, personalized one-on-one health insurance counseling and guidance on Medicare coverage options, benefits, enrollment, appeals, prescription drug plans, and applying for low-income assistance programs like Medicaid, Medicare Savings Program, and Extra Help/Low Income Subsidy; provided via telephone or face-to-face sessions; also includes outreach presentations, enrollment events, and fraud prevention education through Senior Medicare Patrol[1][2][4][5].",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-800-259-5300 or (225) 342-5301[1][3][4][7]", "Website: https://www.ldi.la.gov/consumers/senior-health-shiip (for information, updates signup, and find local counselor)[1][3][4][7]", "In-person or face-to-face: Local counselors available throughout Louisiana (find via website or phone)[4][6]"],
    "processing_time": "Immediate assistance via phone or sessions; no formal application processing[4].",
    "waitlist": null,
    "forms": ["No specific forms required for counseling; may assist with Medicare-related forms during sessions[2]."],
    "documents": ["Medicare card, current plan details, prescription list recommended for counseling sessions but not mandatory[2][4]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Counselors available throughout Louisiana with local assistance; no specified differences in services, wait times, or providers by region[1][4][6].",
    "offices_or_providers": ["State of Louisiana Department of Insurance, P.O. Box 94214, Baton Rouge LA 70804-9214; local counselors statewide[1][4]"]
  },
  "official_source": "https://www.ldi.la.gov/consumers/senior-health-shiip[4]",
  "gotchas": ["Not a healthcare or financial aid program—provides counseling only, does not pay premiums or provide direct benefits; during Medicare Open Enrollment (Oct 15-Dec 7), high demand may require scheduling; must be Medicare beneficiary for core services[2][4][5]", "People miss that it helps with applications for other programs like Extra Help but does not guarantee approval[2]"],
  "data_shape_notes": "no income or asset test; counseling-only service for Medicare beneficiaries statewide via phone/local counselors"
}

{
  "name": "Meals on Wheels - Louisiana Council on Aging",
  "eligibility": {
    "age": 60,
    "income_limits": "No strict income limits statewide; priority given to those with greatest economic/social need, including low-income minority/Native American individuals. Some programs encourage donations ($1-$3/meal) but no one denied for inability to pay. Vary by parish; follows federal poverty guidelines in some cases[1][3].",
    "asset_limits": "No asset limits mentioned across sources.",
    "other_requirements": ["Homebound and unable to shop/cook/prepare meals due to physical disability or mobility issues[1][2][3][4][5][6]", "Live in the service parish/region[3][4]", "Pre-qualified via Governor’s Office of Elderly Affairs assessment tool in some parishes (e.g., Terrebonne)[3]", "No daily family/friend support for meals[4]", "Annual assessments required for ongoing eligibility[4]"]
  },
  "benefits": {
    "type": "service",
    "value": "Home-delivered nutritious meals (1/3 daily nutrition for 60+), low/no salt, customizable for dietary needs; typically 5 meals/week (Mon-Thu hot/fresh + Thu frozen for Fri); may extend to spouse/eligible caregiver[3][4][5].",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Contact local parish Council on Aging (e.g., Terrebonne: terrebonnecoa.org[3]; Caddo: caddocoa.org[4]; Lafayette: laf-coa.org[6]; DeSoto: desotocouncilonaging.com[5])", "Phone national directory: 1-888-998-6325[1]", "In-person or mail via local provider", "Phone/paper/online via local agency; referrals accepted for others[1][2]"],
    "processing_time": "Varies by provider; urgent cases faster[1].",
    "waitlist": "Yes in some parishes (e.g., very long in Caddo Parish)[4]; regional variation.",
    "forms": ["Local application (basic details: name, address, health status); Governor’s Office of Elderly Affairs pre-qualification assessment tool (e.g., Terrebonne)[1][3]"],
    "documents": ["Proof of age (driver’s license/birth certificate)", "Proof of disability (doctor’s note/medical records)", "Proof of income (if requested, not always required)", "Needs assessment/referral from doctor/social worker (some providers)[1][2]"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Parish-specific; must reside in service area of local Council on Aging.",
    "regional_variations": "Administered by local Councils on Aging (e.g., Terrebonne: pre-qual tool, $1 donation[3]; Caddo: 5 meals/week, long waitlist, no charge[4]; DeSoto: $3 suggested donation, Mon-Thu + Fri frozen[5]; Lafayette: health/physical need focus[6]). Meals, donations, waitlists vary.",
    "offices_or_providers": ["Terrebonne Council on Aging (terrebonnecoa.org)[3]", "Caddo Council on Aging (caddocoa.org, 1700 Buckner St., Shreveport)[4]", "DeSoto Council on Aging (desotocouncilonaging.com, Mansfield)[5]", "Lafayette Council on Aging (laf-coa.org)[6]"]
  },
  "official_source": "No single statewide .gov; local parish Councils on Aging sites (e.g., terrebonnecoa.org, caddocoa.org); Governor’s Office of Elderly Affairs assessment tool referenced[3].",
  "gotchas": ["Not emergency service; deliveries require someone home, eat upon delivery[4]", "Long waitlists in high-demand parishes like Caddo[4]", "Must report changes in condition; annual reassessments[4]", "Parish-restricted—not statewide uniform program", "Younger disabled may qualify in some areas but primarily 60+[1]", "Donations encouraged but voluntary; no denial for non-payment[3][4][5]"],
  "data_shape_notes": "Parish-administered by local Councils on Aging with varying providers, wait times, donation amounts, and exact delivery schedules; requires local contact; pre-qual assessment in some areas; priority to greatest need."
}

{
  "name": "Louisiana Respite Care Program",
  "eligibility": {
    "age": null,
    "income_limits": "No specific income limits detailed for a singular 'Louisiana Respite Care Program'; varies by related programs like LT-PCS (Medicaid, income/asset rules apply but exact 2026 figures not listed beyond home equity ≤$752,000) or dementia credit (strict Medicare recipients only, no income test specified).[1][4]",
    "asset_limits": "For LT-PCS (related Medicaid program): Home exempt if applicant lives there/intends to return (equity ≤$752,000 in 2026), spouse/minor child/disabled child lives there. Other assets follow standard Medicaid rules (not detailed here).[1]",
    "other_requirements": ["Varies by sub-program: LT-PCS requires age 65+ or disabled 21+, Nursing Facility Level of Care (NFLOC via LOCET), ability to direct care; OCDD respite for developmental disabilities (age 3+/18+, ICF/IID level); dementia credit requires documented dementia diagnosis and strict Medicare; CSOC for children with special needs; general respite for adults/children with disabilities, special needs, or aging conditions. Caregiver relief need common across.[1][2][4][6][7][9]"]
  },
  "benefits": {
    "type": "service",
    "value": "Short-term relief care: out-of-home center-based respite up to 720 hours per plan of care (POC) year (excess requires approval); includes companion care, host home, shared living (not personal residence); room/board if in approved center; specific examples like dementia credit $2,563 for day programs/in-home sitters up to 4 hours.[4][6]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["OCDD as single point for developmental disabilities respite (contact OCDD); Healthy Louisiana Plan referral for child/youth; general: contact Louisiana Department of Health (LDH) or licensed providers; no central phone/URL listed for unified program.[2][3][7]"],
    "processing_time": "Several weeks to months for provider licensing (not consumer application); unspecified for enrollment.[3]",
    "waitlist": "Enrollment limits indicate potential waitlists (e.g., 2400 for some OCDD by 06/30/2024, 1025 by 06/30/2023).[2]",
    "forms": ["HCBS licensure application (for providers); LOCET for LT-PCS level of care; no specific consumer form named.[1][3]"],
    "documents": ["For providers: financial proof ($50k line of credit, insurance), background checks, policies, business registration. For consumers: diagnosis documentation (e.g., dementia), Medicare confirmation, POC. Criminal background recommended for individual providers.[3][4][7]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None specified; available statewide via LDH/OCDD waivers.",
    "regional_variations": "Enrollment limits and wait times may vary (e.g., by OCDD region); provider availability differs, check local licensing.[2][3]",
    "offices_or_providers": ["Office for Citizens with Developmental Disabilities (OCDD); licensed HCBS providers per LAC 48:I.Chapter 50; Healthy Louisiana Plans.[2][3][6]"]
  },
  "official_source": "https://ldh.la.gov/faq/category/94 (LDH Respite FAQ); https://archrespite.org/wp-content/uploads/2022/09/louisiana.pdf (ARCH overview).[2][7]",
  "gotchas": ["Not a single unified program—respite embedded in waivers (LT-PCS, OCDD, CSOC) or credits (dementia); 720-hour cap per POC year; no respite by legally responsible person/relative in some (varies); must meet specific level of care (NFLOC/ICF/IID); provider licensing strict; check good standing/backgrounds; home equity limits if Medicaid-linked.[1][2][6][7]"],
  "data_shape_notes": "Fragmented across waivers/populations (elderly via LT-PCS/Medicare, DD via OCDD, children via CSOC); hour caps and enrollment limits; provider-focused regs heavy; no central eligibility table—income/assets via Medicaid where applicable."
}

